<span class="line"><span style="color:#FF8FBF">        for</span><span style="color:#C8C8C8">(</span><span style="color:#FF8FBF">int</span><span style="color:#FFFFFF"> j</span><span style="color:#FF8FBF">=</span><span style="color:#B7F7C8">0</span><span style="color:#C8C8C8">;</span><span style="color:#FFFFFF">j</span><span style="color:#FF8FBF">&#x3C;</span><span style="color:#E8ECFF">group</span><span style="color:#C8C8C8">[</span><span style="color:#FFFFFF">i</span><span style="color:#C8C8C8">].</span><span style="color:#FFE08A">size</span><span style="color:#C8C8C8">();</span><span style="color:#FFFFFF">j</span><span style="color:#FF8FBF">++</span><span style="color:#C8C8C8">)</span><span style="color:#FFFFFF"> cout </span><span style="color:#FF8FBF">&#x3C;&#x3C;</span><span style="color:#E8ECFF"> group</span><span style="color:#C8C8C8">[</span><span style="color:#FFFFFF">i</span><span style="color:#C8C8C8">][</span><span style="color:#FFFFFF">j</span><span style="color:#C8C8C8">]</span><span style="color:#FF8FBF"> &#x3C;&#x3C;</span><span style="color:#FFD1E1"> ' '</span><span style="color:#C8C8C8">;</span></span>
